    /// Register a DCTDecode (JPEG-passthrough) image XObject under a fresh name in
    /// `page_no`'s `/Resources /XObject` and return its name. The bytes are opaque
    /// (passthrough), so extraction succeeds without needing a real codec — exactly
    /// what `page_image_elements` reports as `format == "jpeg"`.
    fn register_test_image(doc: &mut Document, page_no: u32, pw: i64, ph: i64) -> Vec<u8> {
        let bytes = vec![0xFFu8, 0xD8, 0xFF, 0xD9]; // tiny opaque "jpeg" payload
        let mut dict = Dictionary::new();
        dict.set(b"Type".to_vec(), Object::Name(b"XObject".to_vec()));
        dict.set(b"Subtype".to_vec(), Object::Name(b"Image".to_vec()));
        dict.set(b"Width".to_vec(), Object::Integer(pw));
        dict.set(b"Height".to_vec(), Object::Integer(ph));
        dict.set(b"BitsPerComponent".to_vec(), Object::Integer(8));
        dict.set(b"ColorSpace".to_vec(), Object::Name(b"DeviceRGB".to_vec()));
        dict.set(b"Filter".to_vec(), Object::Name(b"DCTDecode".to_vec()));
        dict.set(b"Length".to_vec(), Object::Integer(bytes.len() as i64));
        let img_id = (doc.next_object_number(), 0u16);
        doc.objects
            .insert(img_id, Object::Stream(Stream::new(dict, bytes)));
        doc.register_page_resource(page_no, b"XObject", "GpTestImg", Object::Reference(img_id))
            .unwrap()
    }

    /// Build a single page whose content stream mixes, in stream order:
    /// `[text, image, path, image]`. Returns the document plus the two image names.
    /// The unified `ContentElement` indices are therefore: text=0, image=1,
    /// path=2, image=3 — chosen so the per-kind local index (image-local 0,1;
    /// path-local 0) DIFFERS from the unified index, which is the whole point.
    fn page_with_text_image_path_image() -> (Document, Vec<u8>, Vec<u8>) {
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        let im0 = register_test_image(&mut doc, 1, 10, 10);
        let im1 = register_test_image(&mut doc, 1, 20, 20);

        // text → image(im0) → path(rectangle, filled) → image(im1)
        let content = format!(
            "BT /F0 12 Tf 50 750 Td (Hello) Tj ET\n\
             q 40 0 0 40 100 600 cm /{im0} Do Q\n\
             1 0 0 rg 100 400 80 60 re f\n\
             q 30 0 0 30 300 200 cm /{im1} Do Q\n",
            im0 = String::from_utf8_lossy(&im0),
            im1 = String::from_utf8_lossy(&im1),
        );
        doc.set_page_content(1, content.into_bytes()).unwrap();
        (doc, im0, im1)
    }

    #[test]
    fn image_elements_report_unified_index_not_image_local() {
        let (doc, _im0, _im1) = page_with_text_image_path_image();

        // Sanity: the unified element model is [text, image, path, image].
        let elements = doc.page_elements(1).unwrap();
        let kinds: Vec<_> = elements.iter().map(|e| e.kind.clone()).collect();
        assert_eq!(
            kinds,
            vec![
                content::ElementKind::Text,
                content::ElementKind::Image,
                content::ElementKind::Path,
                content::ElementKind::Image,
            ],
            "stream order must be text, image, path, image"
        );

        let imgs = doc.page_image_elements(1);
        assert_eq!(imgs.len(), 2, "two images extracted");
        // Image-local would be 0 and 1; unified is 1 and 3.
        assert_eq!(imgs[0].index, 1, "1st image's unified index is 1, not 0");
        assert_eq!(imgs[1].index, 3, "2nd image's unified index is 3, not 1");

        // Each reported index resolves to an Image element in the unified model.
        for img in &imgs {
            assert_eq!(elements[img.index].kind, content::ElementKind::Image);
        }
    }

    #[test]
    fn image_element_index_roundtrips_through_remove_element() {
        let (mut doc, _im0, _im1) = page_with_text_image_path_image();
        let imgs = doc.page_image_elements(1);
        let second_index = imgs[1].index; // 3
        assert_eq!(second_index, 3);

        // Remove the 2ND image by its reported index. If the index were
        // image-local (1) it would target the wrong unified element; with the
        // unified index (3) it removes exactly that image.
        doc.remove_element(1, second_index).unwrap();

        let after = doc.page_image_elements(1);
        assert_eq!(after.len(), 1, "exactly one image removed");
        assert_eq!(
            after[0].index, 1,
            "the surviving image is the FIRST one (unified index 1)"
        );

        // Text + path survive intact: [text, image, path].
        let kinds: Vec<_> = doc
            .page_elements(1)
            .unwrap()
            .iter()
            .map(|e| e.kind.clone())
            .collect();
        assert_eq!(
            kinds,
            vec![
                content::ElementKind::Text,
                content::ElementKind::Image,
                content::ElementKind::Path,
            ],
            "removing the 2nd image leaves text + 1st image + path"
        );
    }

    #[test]
    fn image_element_index_roundtrips_through_transform_element() {
        let (mut doc, _im0, _im1) = page_with_text_image_path_image();
        let imgs = doc.page_image_elements(1);
        let target = imgs[1].clone(); // 2nd image, unified index 3
        let before_x = target.x;
        let first_x = imgs[0].x;

        // Translate the 2ND image using its reported (unified) index. The transform
        // is applied in the element's own coordinate space (its `cm` is composed
        // after the placement CTM), so we don't assert an exact page-space delta —
        // only that THIS image moved and the OTHER did not.
        doc.transform_element(1, target.index, [1.0, 0.0, 0.0, 1.0, 500.0, 0.0])
            .unwrap();

        let after = doc.page_image_elements(1);
        assert_eq!(after.len(), 2);
        // The 1st image (unified index 1) must be untouched…
        assert!(
            (after[0].x - first_x).abs() < 1e-6,
            "1st image must not move (was {first_x}, now {})",
            after[0].x
        );
        // …and the 2nd image must have shifted in +x (the targeted element).
        assert!(
            after[1].x > before_x + 1.0,
            "2nd image must move right: was {before_x}, now {}",
            after[1].x
        );
    }

    #[test]
    fn replace_image_swaps_pixels_in_place_keeping_object_id_and_do_reference() {
        let (mut doc, _im0, im1) = page_with_text_image_path_image();

        // The 2nd image (unified index 3) is a 20×20 DCTDecode (jpeg) XObject.
        let imgs = doc.page_image_elements(1);
        let target = imgs[1].index; // 3
        assert_eq!(target, 3);
        assert_eq!((imgs[1].pixel_width, imgs[1].pixel_height), (20, 20));
        assert_eq!(imgs[1].format, "jpeg");

        // Capture, BEFORE the swap: the backing object id, the old stream bytes,
        // and the content stream's placement of this image (`cm … /name Do`).
        let id_before = doc.xobject_id(1, &im1).expect("indirect XObject");
        let bytes_before = match doc.objects.get(&id_before) {
            Some(Object::Stream(s)) => s.raw.clone(),
            _ => panic!("expected an image stream"),
        };
        let content_before = String::from_utf8(doc.page_content(1).unwrap()).unwrap();
        let do_op = format!("/{} Do", String::from_utf8_lossy(&im1));
        let placement = "q 30 0 0 30 300 200 cm"; // the 2nd image's CTM, from the fixture
        assert!(content_before.contains(&do_op));
        assert!(content_before.contains(placement));

        // Replace it with a fresh raster of DIFFERENT format AND dimensions: a 32×16
        // opaque PNG → re-encoded to a FlateDecode DeviceRGB stream.
        let rgba = vec![0x80u8; 32 * 16 * 4];
        let png = crate::raster::png::encode_png(32, 16, &rgba);
        doc.replace_image(1, target, &png).unwrap();

        // The object NUMBER is unchanged — every `/Do` keeps resolving to it.
        let id_after = doc.xobject_id(1, &im1).expect("indirect XObject");
        assert_eq!(
            id_after, id_before,
            "object id (and number) must be preserved"
        );

        // The image dict + stream were rewritten: new dimensions, new filter, new
        // bytes.
        let after = doc.page_image_elements(1);
        assert_eq!(after.len(), 2, "still two images");
        assert_eq!(
            (after[1].pixel_width, after[1].pixel_height),
            (32, 16),
            "/Width and /Height now reflect the new raster"
        );
        let stream_after = match doc.objects.get(&id_after) {
            Some(Object::Stream(s)) => s,
            _ => panic!("expected an image stream"),
        };
        assert_eq!(
            stream_after.dict.get(b"Filter").and_then(Object::as_name),
            Some(b"FlateDecode".as_slice()),
            "DCTDecode jpeg replaced by a FlateDecode (PNG-derived) stream"
        );
        assert_eq!(
            stream_after.dict.get(b"Width").and_then(Object::as_i64),
            Some(32)
        );
        assert_eq!(
            stream_after.dict.get(b"Height").and_then(Object::as_i64),
            Some(16)
        );
        assert_ne!(stream_after.raw, bytes_before, "stream bytes changed");

        // The placement (`cm`) and the `/Do` reference are byte-for-byte unchanged:
        // only the pixels were swapped.
        let content_after = String::from_utf8(doc.page_content(1).unwrap()).unwrap();
        assert_eq!(
            content_after, content_before,
            "content stream (every /Do + cm) is untouched by replace_image"
        );

        // The OTHER image (unified index 1) is untouched.
        assert_eq!(after[0].index, 1);
        assert_eq!((after[0].pixel_width, after[0].pixel_height), (10, 10));

        // The whole element model still parses as [text, image, path, image].
        let kinds: Vec<_> = doc
            .page_elements(1)
            .unwrap()
            .iter()
            .map(|e| e.kind.clone())
            .collect();
        assert_eq!(
            kinds,
            vec![
                content::ElementKind::Text,
                content::ElementKind::Image,
                content::ElementKind::Path,
                content::ElementKind::Image,
            ],
        );
    }

    #[test]
    fn replace_image_rejects_non_image_index_and_bad_bytes() {
        let (mut doc, _im0, _im1) = page_with_text_image_path_image();
        // Index 0 is the text element, index 2 is the path — neither is an image.
        assert!(doc
            .replace_image(1, 0, &[0xFFu8, 0xD8, 0xFF, 0xD9])
            .is_err());
        assert!(doc
            .replace_image(1, 2, &[0xFFu8, 0xD8, 0xFF, 0xD9])
            .is_err());
        // A valid image index but undecodable bytes is also rejected.
        assert!(doc.replace_image(1, 3, b"not an image").is_err());
        // And the document is unchanged: the targeted image still reads as 20×20.
        let imgs = doc.page_image_elements(1);
        assert_eq!((imgs[1].pixel_width, imgs[1].pixel_height), (20, 20));
    }

    #[test]
    fn vector_path_index_is_unified_and_roundtrips_through_set_path_style() {
        let (mut doc, _im0, _im1) = page_with_text_image_path_image();

        let paths = doc.page_vector_paths(1).unwrap();
        assert_eq!(paths.len(), 1, "one painted path");
        // Path-local index would be 0; unified index is 2.
        assert_eq!(paths[0].index, 2, "path's unified index is 2, not 0");
        assert_eq!(
            doc.page_elements(1).unwrap()[paths[0].index].kind,
            content::ElementKind::Path
        );

        // Restyle that path (fill → blue) by its reported index. A wrong index (0)
        // would hit the text element and `set_path_style` would error.
        let style = content::PathStyle {
            fill: Some([0.0, 0.0, 1.0]),
            ..Default::default()
        };
        doc.set_path_style(1, paths[0].index, &style).unwrap();

        // The path is still there and now carries the blue fill.
        let after = doc.page_vector_paths(1).unwrap();
        assert_eq!(after.len(), 1);
        assert_eq!(
            after[0].fill,
            Some([0.0, 0.0, 1.0]),
            "fill restyled to blue"
        );
    }

    #[test]
    fn set_text_run_style_splits_a_run_by_index() {
        // Drive the by-run text restyle end-to-end at the Document layer: split the
        // single run "HELLO" so [0,2) turns red, keeping the run's text intact and
        // the page re-parseable. Uses the text-run index (same as replace_text_run).
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        doc.set_page_content(1, b"BT /F1 12 Tf 1 0 0 1 72 700 Tm (HELLO) Tj ET\n".to_vec())
            .unwrap();

        let els = doc.page_text_elements(1);
        let idx = els
            .iter()
            .find(|e| e.text == "HELLO")
            .map(|e| e.index)
            .expect("the run is addressable");

        doc.set_text_run_style(
            1,
            idx,
            &[(0, 2, content::TextStylePatch { color: Some([1.0, 0.0, 0.0]), ..Default::default() })],
        )
        .unwrap();

        // Text is preserved (now shown as two runs "HE" + "LLO"), page still parses.
        let runs = doc.page_text_runs(1).unwrap();
        let joined: String = runs.iter().map(|r| r.text.as_str()).collect();
        assert_eq!(joined, "HELLO", "no glyphs lost by the split");
        let s = String::from_utf8_lossy(&doc.page_content(1).unwrap()).into_owned();
        assert!(s.contains("rg"), "a fill colour op was injected for the span");

        // An index that does not resolve (only one run) is an error.
        assert!(
            doc.set_text_run_style(1, 99, &[(0, 1, content::TextStylePatch::default())]).is_err(),
            "an out-of-range run index fails"
        );
    }

    #[test]
    fn set_path_style_alpha_registers_extgstate_and_injects_gs() {
        // Restyling a path with fill_alpha must (1) create an /ExtGState resource
        // carrying /ca, and (2) inject a `/<name> gs` into the path's content. The
        // path's effective fill alpha is then surfaced by the element walker.
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        doc.set_page_content(1, b"1 0 0 rg 100 100 40 40 re f\n".to_vec())
            .unwrap();

        // No ExtGState before.
        assert!(
            doc.page_gstate_alpha_pair(1).is_empty(),
            "no ExtGState before restyle"
        );

        let style = content::PathStyle {
            fill: Some([1.0, 0.0, 0.0]),
            fill_alpha: Some(0.4),
            ..Default::default()
        };
        doc.set_path_style(1, 0, &style).unwrap();

        // (1) An /ExtGState named like `GpGs*` now carries /ca = 0.4.
        let pairs = doc.page_gstate_alpha_pair(1);
        assert_eq!(pairs.len(), 1, "exactly one ExtGState registered");
        let (name, (ca, _ca_stroke)) = pairs.into_iter().next().unwrap();
        assert!(name.starts_with("GpGs"), "gstate name is GpGs*, got {name}");
        assert!((ca.unwrap() - 0.4).abs() < 1e-9, "/ca recorded as 0.4");

        // (2) The page content now references that gstate via `gs`.
        let content = doc.page_content(1).unwrap();
        let s = String::from_utf8_lossy(&content);
        assert!(
            s.contains(&format!("/{name} gs")),
            "gs op references the gstate"
        );

        // The path's effective fill alpha is now 0.4 (walker resolves the gs).
        let paths = doc.page_vector_paths(1).unwrap();
        assert_eq!(paths.len(), 1);
        assert_eq!(paths[0].fill, Some([1.0, 0.0, 0.0]), "fill restyled red");
        assert!(
            (paths[0].fill_alpha - 0.4).abs() < 1e-9,
            "path fill alpha is 0.4, got {}",
            paths[0].fill_alpha
        );
    }

    #[test]
    fn set_element_opacity_registers_gstate_for_an_image() {
        // An image element gets a registered /ExtGState and a `q /<gs> gs … Q`
        // wrap; the walker then reports the image's fill alpha.
        let (mut doc, _im0, _im1) = page_with_text_image_path_image();
        // Find the first image element's unified index.
        let img_index = doc
            .page_elements(1)
            .unwrap()
            .into_iter()
            .find(|e| e.kind == content::ElementKind::Image)
            .map(|e| e.index)
            .expect("an image element");

        doc.set_element_opacity(1, img_index, 0.25).unwrap();

        let pairs = doc.page_gstate_alpha_pair(1);
        assert!(
            !pairs.is_empty(),
            "ExtGState registered for the image opacity"
        );
        let has_quarter = pairs.values().any(|(ca, ca_stroke)| {
            ca.is_some_and(|v| (v - 0.25).abs() < 1e-9)
                && ca_stroke.is_some_and(|v| (v - 0.25).abs() < 1e-9)
        });
        assert!(has_quarter, "an ExtGState carries /ca = /CA = 0.25");

        // The image's effective alpha is now 0.25 (the wrap reached the Do).
        let img = doc
            .page_elements(1)
            .unwrap()
            .into_iter()
            .find(|e| e.kind == content::ElementKind::Image)
            .unwrap();
        assert!(
            img.fill_alpha.is_some_and(|a| (a - 0.25).abs() < 1e-9),
            "image fill alpha is 0.25, got {:?}",
            img.fill_alpha
        );
    }

    #[test]
    fn reorder_element_moves_op_range_and_keeps_stream_valid() {
        // Two filled shapes then a text run. Bring the first shape to front: it
        // must paint after the text in the stream, the stream must still parse to
        // the same element composition, and the element stays resolvable.
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        doc.set_page_content(
            1,
            b"1 0 0 rg 10 10 20 20 re f\n0 1 0 rg 50 50 20 20 re f\n\
              BT /F0 12 Tf 100 700 Td (Z) Tj ET\n"
                .to_vec(),
        )
        .unwrap();

        doc.reorder_element(1, 0, true).unwrap();

        let content = doc.page_content(1).unwrap();
        let s = String::from_utf8_lossy(&content);
        let tj = s.find("(Z) Tj").unwrap();
        let re = s.find("10 10 20 20 re").unwrap();
        assert!(re > tj, "front-most shape now painted after the text");

        // Stream still parses to two paths + one text run.
        let kinds: Vec<_> = doc
            .page_elements(1)
            .unwrap()
            .iter()
            .map(|e| e.kind.clone())
            .collect();
        assert_eq!(
            kinds
                .iter()
                .filter(|k| **k == content::ElementKind::Path)
                .count(),
            2
        );
        assert_eq!(
            kinds
                .iter()
                .filter(|k| **k == content::ElementKind::Text)
                .count(),
            1
        );
    }

    #[test]
    fn render_page_excluding_omits_the_chosen_element() {
        // A page with a single filled red box: excluding its element index must
        // produce a raster with strictly fewer painted pixels than the full
        // render (the box is gone), while excluding nothing equals the full page.
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        doc.set_page_content(1, b"1 0 0 rg 100 100 200 200 re f\n".to_vec())
            .unwrap();

        let box_index = doc
            .page_elements(1)
            .unwrap()
            .into_iter()
            .find(|e| e.kind == content::ElementKind::Path)
            .map(|e| e.index)
            .expect("the box element");

        let full = doc.render_page(1, 1.0).unwrap();
        let excluding = doc.render_page_excluding(1, &[box_index], 1.0).unwrap();
        let none = doc.render_page_excluding(1, &[], 1.0).unwrap();

        assert_ne!(full, excluding, "excluding the box changes the raster");
        assert_eq!(full, none, "excluding nothing equals the full render");

        let count_nonwhite = |png: &[u8]| -> usize {
            crate::raster::decode_png(png)
                .expect("valid PNG")
                .rgba
                .chunks_exact(4)
                .filter(|px| px[0] != 255 || px[1] != 255 || px[2] != 255)
                .count()
        };
        let n_full = count_nonwhite(&full);
        let n_excl = count_nonwhite(&excluding);
        assert!(n_full > 0, "full render paints the red box ({n_full} px)");
        assert!(
            n_excl < n_full,
            "excluded render has fewer painted pixels ({n_excl}) than full ({n_full})"
        );
    }

    #[test]
    fn vector_path_index_skips_clip_only_paths() {
        // [text, clip-only path (W n → Path element but NO VectorPath), painted
        // path]. The painted path's unified index must be 2 (after text=0 and the
        // clip-only Path element=1), proving the correlation is robust to the
        // element/vector count divergence.
        let pdf = crate::convert::reverse::txt_to_pdf("seed");
        let mut doc = Document::open(&pdf).unwrap();
        let content = b"BT /F0 12 Tf 50 750 Td (Hi) Tj ET\n\
                        0 0 50 50 re W n\n\
                        1 0 0 rg 100 100 40 40 re f\n"
            .to_vec();
        doc.set_page_content(1, content).unwrap();

        let kinds: Vec<_> = doc
            .page_elements(1)
            .unwrap()
            .iter()
            .map(|e| e.kind.clone())
            .collect();
        assert_eq!(
            kinds,
            vec![
                content::ElementKind::Text,
                content::ElementKind::Path, // clip-only `… W n`
                content::ElementKind::Path, // the painted `re f`
            ],
            "clip-only path is a Path element too"
        );

        let paths = doc.page_vector_paths(1).unwrap();
        assert_eq!(paths.len(), 1, "only the painted path is a VectorPath");
        assert_eq!(
            paths[0].index, 2,
            "painted path's unified index is 2 (clip-only path took index 1)"
        );

        // And that unified index restyles the painted path, not the clip path.
        // (The painted path is filled, so we override its fill.)
        let style = content::PathStyle {
            fill: Some([0.0, 1.0, 0.0]),
            ..Default::default()
        };
        doc.set_path_style(1, paths[0].index, &style).unwrap();
        let after = doc.page_vector_paths(1).unwrap();
        assert_eq!(after[0].fill, Some([0.0, 1.0, 0.0]));
    }

