    #[test]
    fn jbig2_image_resolves_indirect_globals_same_as_inline() {
        // A JBIG2 image whose shared content (here the page-info segment plus a
        // generic region) lives in a SEPARATE globals stream referenced by
        // `/DecodeParms << /JBIG2Globals N 0 R >>` — the common scanned-document
        // shape. The filter layer is document-free and cannot follow that `N 0 R`;
        // `decode_image_stream` resolves it. This asserts the indirect-globals
        // form decodes the SAME bitmap as the equivalent inline-globals form, and
        // that without the globals the page cannot decode at all (proving the
        // globals are genuinely fed into the JBIG2 decoder).

        // --- Minimal JBIG2 segment builders (mirroring the wire format) ---
        fn push_segment(out: &mut Vec<u8>, number: u32, seg_type: u8, data: &[u8]) {
            out.extend_from_slice(&number.to_be_bytes());
            out.push(seg_type); // flags: type, 1-byte page association
            out.push(0x00); // referred-to count 0 + retention flags
            out.push(1); // page association
            out.extend_from_slice(&(data.len() as u32).to_be_bytes());
            out.extend_from_slice(data);
        }
        // Page-information segment (type 48) for a `w x h` page, no default pixel.
        fn page_info(w: u32, h: u32) -> Vec<u8> {
            let mut v = Vec::new();
            v.extend_from_slice(&w.to_be_bytes());
            v.extend_from_slice(&h.to_be_bytes());
            v.extend_from_slice(&0u32.to_be_bytes()); // xres
            v.extend_from_slice(&0u32.to_be_bytes()); // yres
            v.push(0x00); // flags
            v.extend_from_slice(&0u16.to_be_bytes()); // striping
            v
        }
        // Immediate generic-region segment (type 38), MMR-coded. The payload
        // `0x31 0xF8` decodes (G4) to `WWW BB WWW` over its 8x2 region; placed at
        // `(0, y)` with comb-op OR onto the page.
        fn generic_region_mmr(y: u32) -> Vec<u8> {
            let mut region = Vec::new();
            region.extend_from_slice(&8u32.to_be_bytes()); // width
            region.extend_from_slice(&2u32.to_be_bytes()); // height
            region.extend_from_slice(&0u32.to_be_bytes()); // x
            region.extend_from_slice(&y.to_be_bytes()); // y
            region.push(0x00); // comb-op OR
            region.push(0x01); // generic flags: MMR
            region.extend_from_slice(&[0x31u8, 0xF8]); // MMR data → WWW BB WWW rows
            region
        }

        // Globals stream: page-info(8x4) + a generic region painting rows 0..2.
        let mut globals_segments: Vec<u8> = Vec::new();
        push_segment(&mut globals_segments, 0, 48, &page_info(8, 4));
        push_segment(&mut globals_segments, 1, 38, &generic_region_mmr(0));
        // Page stream: a second generic region painting rows 2..4.
        let mut page_segments: Vec<u8> = Vec::new();
        push_segment(&mut page_segments, 2, 38, &generic_region_mmr(2));

        // Build a host document so indirect references can be resolved.
        let pdf = crate::convert::reverse::txt_to_pdf("jbig2 host");
        let mut doc = Document::open(&pdf).unwrap();

        // Register the globals as a standalone (Flate-compressed) stream object so
        // its `/JBIG2Globals` reference exercises BOTH indirect resolution AND the
        // globals' own filter chain inside `decode_stream`.
        let globals_raw = crate::filters::deflate::flate_encode(&globals_segments);
        let mut globals_dict = Dictionary::new();
        globals_dict.set(b"Filter".to_vec(), Object::Name(b"FlateDecode".to_vec()));
        globals_dict.set(
            b"Length".to_vec(),
            Object::Integer(globals_raw.len() as i64),
        );
        let globals_id = (doc.next_object_number(), 0u16);
        doc.objects.insert(
            globals_id,
            Object::Stream(Stream::new(globals_dict.clone(), globals_raw.clone())),
        );

        // Helper: a JBIG2 image XObject (8x4, 1-bit DeviceGray) carrying the given
        // `/DecodeParms` object.
        let image_stream = |decode_parms: Object| -> Stream {
            let mut dict = Dictionary::new();
            dict.set(b"Type".to_vec(), Object::Name(b"XObject".to_vec()));
            dict.set(b"Subtype".to_vec(), Object::Name(b"Image".to_vec()));
            dict.set(b"Width".to_vec(), Object::Integer(8));
            dict.set(b"Height".to_vec(), Object::Integer(4));
            dict.set(b"BitsPerComponent".to_vec(), Object::Integer(1));
            dict.set(b"ColorSpace".to_vec(), Object::Name(b"DeviceGray".to_vec()));
            dict.set(b"Filter".to_vec(), Object::Name(b"JBIG2Decode".to_vec()));
            dict.set(b"DecodeParms".to_vec(), decode_parms);
            Stream::new(dict, page_segments.clone())
        };

        // (a) Indirect: `/JBIG2Globals` is `globals_id 0 R`.
        let mut indirect_parms = Dictionary::new();
        indirect_parms.set(b"JBIG2Globals".to_vec(), Object::Reference(globals_id));
        let indirect_img = doc
            .decode_image_stream(&image_stream(Object::Dictionary(indirect_parms)))
            .expect("indirect-globals JBIG2 image decodes");

        // (b) Inline: `/JBIG2Globals` is the resolved stream object itself.
        let mut inline_parms = Dictionary::new();
        inline_parms.set(
            b"JBIG2Globals".to_vec(),
            Object::Stream(Stream::new(globals_dict, globals_raw)),
        );
        let inline_img = doc
            .decode_image_stream(&image_stream(Object::Dictionary(inline_parms)))
            .expect("inline-globals JBIG2 image decodes");

        // The core assertion: the two forms decode to the identical bitmap.
        assert_eq!(
            (indirect_img.width, indirect_img.height),
            (inline_img.width, inline_img.height),
            "indirect and inline globals must yield the same geometry"
        );
        assert_eq!(
            indirect_img.rgba, inline_img.rgba,
            "indirect /JBIG2Globals must decode the SAME pixels as the inline form"
        );

        // Sanity: the decoded image must show the `WWW BB WWW` pattern (black at
        // x=3,4 on every row), which can only come from the globals' page-info +
        // region plus the page region — i.e. the globals really were fed in. The
        // image is 8x4 RGBA; gray 0 = black, gray 255 = white.
        let px = |x: usize, y: usize| -> u8 { indirect_img.rgba[(y * 8 + x) * 4] };
        for y in 0..4 {
            for x in 0..8 {
                let expect_black = x == 3 || x == 4; // BB columns of WWW BB WWW
                assert_eq!(
                    px(x, y) == 0,
                    expect_black,
                    "pixel ({x},{y}) colour mismatch (the globals region must paint)"
                );
            }
        }

        // Without the globals, the page stream alone has no page-info segment, so
        // the JBIG2 decode fails and the image cannot be produced. This is exactly
        // the pre-fix behaviour for an unresolved indirect `/JBIG2Globals`.
        let no_globals = image_stream(Object::Null);
        assert!(
            doc.decode_image_stream(&no_globals).is_none(),
            "without globals the JBIG2 page cannot decode (proves globals drive the result)"
        );
    }

    #[test]
    fn draw_svg_image_emits_filtered_raster_as_image_with_smask() {
        // An SVG whose only content is a blur-filtered rect: `draw_svg_image`
        // must place the filtered raster as an /Image XObject (a `Do` op) whose
        // soft edge is carried by a /DeviceGray /SMask.
        let svg = r##"<svg viewBox="0 0 80 80">
            <filter id="blur" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3"/>
            </filter>
            <rect x="20" y="20" width="40" height="40" fill="#ff0000" filter="url(#blur)"/>
        </svg>"##;
        let img = crate::svg::parse_svg(svg).expect("filtered SVG parses");
        assert!(
            img.prims.is_empty() && img.rasters.len() == 1,
            "the filter produced one raster and no vector prims"
        );

        let pdf = crate::convert::reverse::txt_to_pdf("svg filter host page");
        let mut doc = Document::open(&pdf).unwrap();
        doc.draw_svg_image(1, &img, 100.0, 100.0, 160.0, 160.0)
            .unwrap();

        // The page content references an image XObject via a `Do` operator.
        let content = doc.page_content(1).unwrap();
        let do_count = content
            .windows(3)
            .filter(|w| w == b"Do\n" || *w == b"Do ")
            .count();
        assert!(
            do_count >= 1,
            "the filtered raster is drawn with a `Do` op (found {do_count})"
        );

        // An image XObject carrying a /SMask was emitted for the soft alpha.
        let has_image_with_smask = doc.objects.values().any(|o| {
            if let Object::Stream(s) = o {
                let is_image = s
                    .dict
                    .get(b"Subtype")
                    .and_then(Object::as_name)
                    .map(|n| n == b"Image")
                    .unwrap_or(false);
                is_image && s.dict.get(b"SMask").is_some()
            } else {
                false
            }
        });
        assert!(
            has_image_with_smask,
            "the filtered raster is embedded as an /Image with an alpha /SMask"
        );

        // It survives a save/reopen round-trip as an image element on the page.
        let reopened = Document::open(&doc.save()).unwrap();
        assert!(
            !reopened.page_image_elements(1).is_empty(),
            "the filtered raster persists as an image element after round-trip"
        );
    }

    // ─── gradient per-stop varying alpha → luminosity soft mask ──────────────

    /// A one-prim `SvgImage` whose single rectangle (`0,0 → 80,80` in viewBox
    /// space) is filled with `grad`. Drives the gradient fill site of
    /// `draw_svg_image` without depending on the SVG parser.
    fn svg_image_with_gradient(grad: crate::svg::Gradient) -> crate::svg::SvgImage {
        use crate::content::svg_path::Seg;
        use crate::svg::{Fill, Prim, SvgImage};
        let segs = vec![
            Seg::Move(0.0, 0.0),
            Seg::Line(80.0, 0.0),
            Seg::Line(80.0, 80.0),
            Seg::Line(0.0, 80.0),
            Seg::Close,
        ];
        SvgImage {
            width: 80.0,
            height: 80.0,
            view_box: [0.0, 0.0, 80.0, 80.0],
            prims: vec![Prim {
                segs,
                fill: Some(Fill::Gradient(grad)),
                stroke: None,
                stroke_w: 0.0,
                fill_opacity: 1.0,
                stroke_opacity: 1.0,
            }],
            rasters: Vec::new(),
        }
    }

    /// Find a luminosity `/SMask` `/ExtGState` in a page's `/Resources` and
    /// return its `/G` form-group object id (the transparency-group form
    /// XObject), if any was emitted. The gstate dicts are registered inline in
    /// the page's `/ExtGState` sub-dictionary (not as top-level objects).
    fn find_luminosity_smask_group(doc: &Document, page_no: u32) -> Option<ObjectId> {
        let resources = doc.page_resources(page_no);
        let gstates = doc.resolve(resources.get(b"ExtGState")?).as_dict()?.clone();
        gstates.0.values().find_map(|o| {
            let gs = doc.resolve(o).as_dict()?.clone();
            let smask = doc.resolve(gs.get(b"SMask")?).as_dict()?.clone();
            if smask.get(b"S").and_then(Object::as_name) != Some(b"Luminosity".as_slice()) {
                return None;
            }
            smask.get(b"G").and_then(Object::as_reference)
        })
    }

    /// Whether a page's `/Resources` carry a `/Pattern` shading whose `/Shading`
    /// uses the given colour space (e.g. `DeviceRGB`).
    fn page_has_pattern_colorspace(doc: &Document, page_no: u32, cs: &[u8]) -> bool {
        let resources = doc.page_resources(page_no);
        let Some(patterns) = resources
            .get(b"Pattern")
            .map(|o| doc.resolve(o))
            .and_then(Object::as_dict)
        else {
            return false;
        };
        patterns.0.values().any(|o| {
            doc.resolve(o)
                .as_dict()
                .and_then(|p| p.get(b"Shading"))
                .map(|o| doc.resolve(o))
                .and_then(|sh| sh.as_dict().and_then(|d| d.get(b"ColorSpace")).cloned())
                .and_then(|o| o.as_name().map(<[u8]>::to_vec))
                .as_deref()
                == Some(cs)
        })
    }

    /// The DeviceGray shading + its 256 raw function bytes from a soft-mask form
    /// group: the form's `/Resources/Shading/Sh0` is the shading, its `/Function`
    /// resolves to the sampled stream.
    fn smask_gray_shading(doc: &Document, group_id: ObjectId) -> (Dictionary, Vec<u8>) {
        let form = doc
            .objects
            .get(&group_id)
            .and_then(Object::as_stream)
            .expect("soft-mask group is a form stream");
        // It is a transparency group in DeviceGray.
        let group = form.dict.get(b"Group").and_then(Object::as_dict).unwrap();
        assert_eq!(
            group.get(b"S").and_then(Object::as_name),
            Some(b"Transparency".as_slice()),
            "the form is a transparency group"
        );
        assert_eq!(
            group.get(b"CS").and_then(Object::as_name),
            Some(b"DeviceGray".as_slice()),
            "the transparency group colour space is DeviceGray"
        );
        let res = form
            .dict
            .get(b"Resources")
            .and_then(Object::as_dict)
            .unwrap();
        let shadings = res.get(b"Shading").and_then(Object::as_dict).unwrap();
        let sh = shadings
            .get(b"Sh0")
            .and_then(Object::as_dict)
            .unwrap()
            .clone();
        assert_eq!(
            sh.get(b"ColorSpace").and_then(Object::as_name),
            Some(b"DeviceGray".as_slice()),
            "the mask shading is DeviceGray"
        );
        let fn_ref = sh.get(b"Function").and_then(Object::as_reference).unwrap();
        let samples = doc
            .objects
            .get(&fn_ref)
            .and_then(Object::as_stream)
            .expect("the mask function is a sampled stream")
            .raw
            .clone();
        (sh, samples)
    }

    #[test]
    fn svg_axial_varying_alpha_emits_luminosity_devicegray_smask() {
        use crate::svg::{GradKind, GradStop, Gradient};
        // A 2-stop axial gradient fading opaque → transparent (alpha 1.0 → 0.0).
        let grad = Gradient {
            kind: GradKind::Linear {
                x1: 0.0,
                y1: 0.0,
                x2: 80.0,
                y2: 0.0,
            },
            stops: vec![
                GradStop {
                    offset: 0.0,
                    rgb: [1.0, 0.0, 0.0],
                    alpha: 1.0,
                },
                GradStop {
                    offset: 1.0,
                    rgb: [0.0, 0.0, 1.0],
                    alpha: 0.0,
                },
            ],
        };
        let img = svg_image_with_gradient(grad);

        let pdf = crate::convert::reverse::txt_to_pdf("gradient alpha host");
        let mut doc = Document::open(&pdf).unwrap();
        doc.draw_svg_image(1, &img, 100.0, 100.0, 160.0, 160.0)
            .unwrap();

        // A luminosity soft-mask gstate (named GpSm*) was emitted and is applied
        // in the page content via a `gs` op.
        let group_id = find_luminosity_smask_group(&doc, 1)
            .expect("a /Luminosity /SMask ExtGState is emitted for varying alpha");
        let content = doc.page_content(1).unwrap();
        let s = String::from_utf8_lossy(&content);
        assert!(
            s.contains("/GpSm"),
            "the soft-mask gstate is applied (`/GpSm* gs`)"
        );
        // The colour shading pattern is still emitted (the fill itself).
        assert!(
            s.contains("/Pattern cs"),
            "the colour shading pattern still fills"
        );

        // The mask is a DeviceGray ShadingType-2 (axial) shading; its 256-sample
        // function spans 255 (first stop, opaque → shown) → 0 (last, hidden).
        let (sh, samples) = smask_gray_shading(&doc, group_id);
        assert_eq!(
            sh.get(b"ShadingType").and_then(Object::as_i64),
            Some(2),
            "axial gradient → ShadingType 2 mask"
        );
        assert_eq!(samples.len(), 256, "256 grey alpha samples");
        assert_eq!(
            samples[0], 255,
            "first stop alpha 1.0 → luminance 255 (shown)"
        );
        assert_eq!(
            samples[255], 0,
            "last stop alpha 0.0 → luminance 0 (fully masked)"
        );
        // Monotonically decreasing (a clean fade, not a uniform mean).
        assert!(
            samples.windows(2).all(|w| w[0] >= w[1]),
            "the alpha ramp decreases monotonically across the axis"
        );
        assert!(
            samples.iter().any(|&v| v > 0 && v < 255),
            "intermediate alphas exist (this is NOT a single uniform `ca`)"
        );
    }

    #[test]
    fn svg_radial_varying_alpha_emits_devicegray_shadingtype3_mask() {
        use crate::svg::{GradKind, GradStop, Gradient};
        // A 3-stop radial gradient with varying alpha (1.0 → 0.5 → 0.0).
        let grad = Gradient {
            kind: GradKind::Radial {
                cx: 40.0,
                cy: 40.0,
                r: 40.0,
                fx: 40.0,
                fy: 40.0,
            },
            stops: vec![
                GradStop {
                    offset: 0.0,
                    rgb: [1.0, 1.0, 1.0],
                    alpha: 1.0,
                },
                GradStop {
                    offset: 0.5,
                    rgb: [0.5, 0.5, 0.5],
                    alpha: 0.5,
                },
                GradStop {
                    offset: 1.0,
                    rgb: [0.0, 0.0, 0.0],
                    alpha: 0.0,
                },
            ],
        };
        let img = svg_image_with_gradient(grad);

        let pdf = crate::convert::reverse::txt_to_pdf("radial alpha host");
        let mut doc = Document::open(&pdf).unwrap();
        doc.draw_svg_image(1, &img, 50.0, 50.0, 120.0, 120.0)
            .unwrap();

        let group_id = find_luminosity_smask_group(&doc, 1)
            .expect("a /Luminosity /SMask ExtGState is emitted for the radial gradient");
        let (sh, samples) = smask_gray_shading(&doc, group_id);
        assert_eq!(
            sh.get(b"ShadingType").and_then(Object::as_i64),
            Some(3),
            "radial gradient → ShadingType 3 mask"
        );
        assert_eq!(samples.len(), 256);
        assert_eq!(samples[0], 255, "centre alpha 1.0 → 255");
        assert_eq!(samples[255], 0, "rim alpha 0.0 → 0");
        // The mid stop (offset 0.5, alpha 0.5) lands near 128.
        assert!(
            (samples[128] as i32 - 128).abs() <= 2,
            "mid stop alpha 0.5 → ~128, got {}",
            samples[128]
        );
    }

    #[test]
    fn svg_all_opaque_gradient_uses_simple_path_no_smask() {
        use crate::svg::{GradKind, GradStop, Gradient};
        // Both stops fully opaque → the cheap path (no luminosity soft mask).
        let grad = Gradient {
            kind: GradKind::Linear {
                x1: 0.0,
                y1: 0.0,
                x2: 80.0,
                y2: 0.0,
            },
            stops: vec![
                GradStop {
                    offset: 0.0,
                    rgb: [1.0, 0.0, 0.0],
                    alpha: 1.0,
                },
                GradStop {
                    offset: 1.0,
                    rgb: [0.0, 0.0, 1.0],
                    alpha: 1.0,
                },
            ],
        };
        let img = svg_image_with_gradient(grad);

        let pdf = crate::convert::reverse::txt_to_pdf("opaque gradient host");
        let mut doc = Document::open(&pdf).unwrap();
        doc.draw_svg_image(1, &img, 100.0, 100.0, 160.0, 160.0)
            .unwrap();

        // The colour shading is emitted, but NO luminosity soft mask.
        let content = doc.page_content(1).unwrap();
        let s = String::from_utf8_lossy(&content);
        assert!(
            s.contains("/Pattern cs"),
            "the gradient still fills via a pattern"
        );
        assert!(
            find_luminosity_smask_group(&doc, 1).is_none(),
            "an all-opaque gradient must NOT emit a /Luminosity /SMask"
        );
        assert!(
            !s.contains("/GpSm"),
            "no soft-mask gstate is applied for an all-opaque gradient"
        );
    }

    #[test]
    fn colrv1_shaped_uniform_alpha_gradient_emits_no_alpha_smask() {
        use crate::svg::{GradKind, GradStop, Gradient};
        // The COLRv1 colour path calls `register_svg_shading` directly with a
        // gradient whose stops share one (uniform) alpha and handles opacity
        // separately. Register that exact call shape and assert it produces only
        // the colour /Pattern — never a luminosity soft mask.
        let grad = Gradient {
            kind: GradKind::Linear {
                x1: 0.0,
                y1: 0.0,
                x2: 100.0,
                y2: 0.0,
            },
            stops: vec![
                GradStop {
                    offset: 0.0,
                    rgb: [1.0, 0.0, 0.0],
                    alpha: 0.7,
                },
                GradStop {
                    offset: 1.0,
                    rgb: [0.0, 0.0, 1.0],
                    alpha: 0.7,
                },
            ],
        };

        let pdf = crate::convert::reverse::txt_to_pdf("colrv1 shape host");
        let mut doc = Document::open(&pdf).unwrap();
        let identity = |fx: f64, fy: f64| (fx, fy);
        let name = doc
            .register_svg_shading(1, &grad, identity, 1.0)
            .unwrap()
            .expect("the colour shading pattern registers");
        assert!(name.starts_with(b"GpSh"), "colour pattern named GpSh*");

        // The colour pattern is a DeviceRGB shading pattern (the COLRv1 path's
        // only output here); no soft mask is emitted on this path.
        assert!(
            page_has_pattern_colorspace(&doc, 1, b"DeviceRGB"),
            "the colour shading is DeviceRGB"
        );
        assert!(
            find_luminosity_smask_group(&doc, 1).is_none(),
            "the COLRv1 colour call must NOT emit a luminosity soft mask"
        );
        // And no DeviceGray shading leaked from this path.
        let has_gray_shading = doc.objects.values().any(|o| {
            if let Object::Stream(s) = o {
                s.dict
                    .get(b"Resources")
                    .and_then(Object::as_dict)
                    .and_then(|r| r.get(b"Shading"))
                    .is_some()
            } else {
                false
            }
        });
        assert!(!has_gray_shading, "no soft-mask form group emitted");
    }

    #[test]
    fn deletes_a_page() {
        let mut doc = Document::open(&fixture("multi-page.pdf")).unwrap();
        let before = doc.page_count();
        assert!(before > 1, "fixture should have several pages");
        doc.delete_page(1).unwrap();
        let reopened = Document::open(&doc.save()).unwrap();
        assert_eq!(reopened.page_count(), before - 1);
    }

    #[test]
    fn moves_a_page() {
        let mut doc = Document::open(&fixture("multi-page.pdf")).unwrap();
        let ids = doc.page_ids().unwrap();
        assert!(ids.len() >= 2);
        let first = ids[0];

        doc.move_page(1, ids.len() as u32).unwrap();
        let reordered = doc.page_ids().unwrap();
        assert_eq!(reordered.len(), ids.len());
        assert_eq!(
            reordered.last().copied(),
            Some(first),
            "page 1 moved to last"
        );

        assert_eq!(Document::open(&doc.save()).unwrap().page_count(), ids.len());
    }

    #[test]
    fn extracts_a_single_page() {
        let doc = Document::open(&fixture("multi-page.pdf")).unwrap();
        assert!(doc.page_count() >= 2);
        let extracted = doc.extract_pages(&[1]).unwrap();
        let reopened = Document::open(&extracted).unwrap();
        assert_eq!(reopened.page_count(), 1, "extracted exactly one page");
    }

    #[test]
    fn merges_pages_from_another_pdf() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let before = doc.page_count();
        let other = fixture("multi-page.pdf");
        let other_count = Document::open(&other).unwrap().page_count();

        doc.append_pages_from(&other).unwrap();
        let reopened = Document::open(&doc.save()).unwrap();
        assert_eq!(reopened.page_count(), before + other_count, "pages merged");
    }

    #[test]
    fn appends_a_page_range_selection_from_another_pdf() {
        // `multi-page.pdf` has 5 pages; each page's text reads "Page N of 5".
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let before = doc.page_count();
        let other = fixture("multi-page.pdf");

        // Bring in only pages 2 and 4 of the source, in that order.
        doc.append_pages_from_subset(&other, &[2, 4]).unwrap();

        let reopened = Document::open(&doc.save()).unwrap();
        assert_eq!(
            reopened.page_count(),
            before + 2,
            "only the two selected pages were appended"
        );

        // The two appended pages are the last two; their distinctive marks survive…
        let page_text = |n: u32| -> String {
            reopened
                .page_text_runs(n)
                .unwrap_or_default()
                .iter()
                .map(|r| r.text.clone())
                .collect::<Vec<_>>()
                .join(" ")
        };
        let appended_a = page_text(before as u32 + 1);
        let appended_b = page_text(before as u32 + 2);
        assert!(
            appended_a.contains("Page 2 of 5"),
            "first appended page kept its content: {appended_a:?}"
        );
        assert!(
            appended_b.contains("Page 4 of 5"),
            "second appended page kept its content: {appended_b:?}"
        );

        // …and the unselected source pages were NOT imported.
        let all_text: String = (1..=reopened.page_count() as u32).map(page_text).collect();
        assert!(
            !all_text.contains("Page 1 of 5"),
            "unselected page 1 was not imported"
        );
        assert!(
            !all_text.contains("Page 3 of 5"),
            "unselected page 3 was not imported"
        );
        assert!(
            !all_text.contains("Page 5 of 5"),
            "unselected page 5 was not imported"
        );
    }

    #[test]
    fn append_page_range_rejects_an_all_out_of_range_selection() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let before = doc.page_count();
        let other = fixture("multi-page.pdf");
        // `multi-page.pdf` has 5 pages — 6 and 99 are both past the end. As with
        // `extract_pages`, out-of-range 1-based numbers are dropped, so the
        // selection is empty and the call is rejected.
        assert!(doc.append_pages_from_subset(&other, &[6, 99]).is_err());
        // The destination is untouched after the rejected call.
        assert_eq!(
            doc.page_count(),
            before,
            "no pages appended on empty selection"
        );
    }

