    #[test]
    fn signs_a_document() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let randomness: Vec<u8> = (0..256).map(|i| (i * 53 + 7) as u8).collect();
        let signer = crate::sign::Signer::generate(
            "GigaPDF Tester",
            "260614000000Z",
            "360614000000Z",
            512,
            &randomness,
        )
        .unwrap();

        let signed = doc
            .sign(&signer, "GigaPDF Tester", "Approval", "D:20260614120000Z")
            .unwrap();

        assert_eq!(&signed[0..5], b"%PDF-", "valid PDF header");
        // The fixed-width /ByteRange placeholders were patched with real offsets.
        assert!(
            !signed.windows(10).any(|w| w == b"9999999999"),
            "ByteRange placeholders patched"
        );
        let text = String::from_utf8_lossy(&signed);
        assert!(
            text.contains("adbe.pkcs7.detached"),
            "detached signature subfilter"
        );
        assert!(text.contains("/ByteRange"), "byte range present");
        // The signed file still parses as a structurally valid PDF.
        let reopened = Document::open(&signed).unwrap();
        assert!(reopened.page_count() >= 1, "signed PDF re-opens");
    }

    #[test]
    fn verifies_its_own_signature_and_detects_tampering() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let randomness: Vec<u8> = (0..256).map(|i| (i * 53 + 7) as u8).collect();
        let signer = crate::sign::Signer::generate(
            "CN Tester",
            "260614000000Z",
            "360614000000Z",
            1024,
            &randomness,
        )
        .unwrap();
        let signed = doc
            .sign(&signer, "Jane Signer", "Approval", "D:20260614120000Z")
            .unwrap();

        let reopened = Document::open(&signed).unwrap();

        // signatures() lists the embedded signature with its metadata.
        let sigs = reopened.signatures();
        assert_eq!(sigs.len(), 1, "one signature listed");
        assert_eq!(sigs[0].signer_name.as_deref(), Some("Jane Signer"));
        assert_eq!(sigs[0].reason.as_deref(), Some("Approval"));
        assert_eq!(sigs[0].sub_filter.as_deref(), Some("adbe.pkcs7.detached"));
        assert!(sigs[0].byte_range[1] > 0, "ByteRange has a real length");

        // verify_signatures() validates against the original bytes.
        let ok = reopened.verify_signatures(&signed);
        assert_eq!(ok.len(), 1);
        assert!(ok[0].byte_range_ok, "byte range well-formed");
        assert!(ok[0].digest_ok, "messageDigest matches the covered bytes");
        assert!(ok[0].signature_ok, "RSA signature validates");
        assert!(ok[0].covers_whole_document, "covers the whole file");
        assert_eq!(ok[0].algorithm, "RSA+SHA-256");
        assert!(ok[0].cert_count >= 1, "embeds the signer certificate");
        assert_eq!(ok[0].signer_common_name.as_deref(), Some("CN Tester"));

        // Tampering a covered byte breaks the digest (signature over signedAttrs
        // is still intact, but the content no longer hashes to messageDigest).
        let mut tampered = signed.clone();
        tampered[60] ^= 0xFF;
        let bad = reopened.verify_signatures(&tampered);
        assert!(!bad[0].digest_ok, "tampered content fails the digest check");

        // Appending bytes after the signature => it no longer covers the file.
        let mut appended = signed.clone();
        appended.extend_from_slice(b"\n% trailing change\n");
        let cov = reopened.verify_signatures(&appended);
        assert!(
            !cov[0].covers_whole_document,
            "appended bytes are outside the ByteRange"
        );
        assert!(cov[0].digest_ok, "the covered region is still intact");
    }

    #[test]
    fn certifies_a_document_with_docmdp() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let randomness: Vec<u8> = (0..256).map(|i| (i * 17 + 3) as u8).collect();
        let signer = crate::sign::Signer::generate(
            "Certifier",
            "260101000000Z",
            "360101000000Z",
            1024,
            &randomness,
        )
        .unwrap();
        let signed = doc
            .sign_certify(
                &signer,
                "Certifier",
                "I certify this",
                "D:20260624000000Z",
                2,
            )
            .unwrap();

        let reopened = Document::open(&signed).unwrap();
        // The catalog carries /Perms /DocMDP → the certifying signature.
        let catalog = reopened.catalog().unwrap();
        let perms = catalog
            .get(b"Perms")
            .map(|o| reopened.resolve(o))
            .and_then(Object::as_dict)
            .expect("/Perms present");
        assert!(perms.get(b"DocMDP").is_some(), "/Perms /DocMDP set");
        // The signature dict has a DocMDP /Reference with the permission level.
        let sig = reopened
            .resolve(perms.get(b"DocMDP").unwrap())
            .as_dict()
            .unwrap();
        let sigref = reopened
            .resolve(sig.get(b"Reference").unwrap())
            .as_array()
            .and_then(|a| a.first())
            .map(|o| reopened.resolve(o))
            .and_then(Object::as_dict)
            .expect("/Reference SigRef");
        assert_eq!(
            sigref.get(b"TransformMethod").and_then(Object::as_name),
            Some(b"DocMDP".as_slice())
        );
        // And it still verifies cryptographically.
        let rep = reopened.verify_signatures(&signed);
        assert!(
            rep[0].digest_ok && rep[0].signature_ok,
            "certified sig verifies"
        );
    }

    #[test]
    fn signs_a_document_with_an_imported_p12_identity() {
        // A real OpenSSL .p12 (PBES2/AES) imported and used to sign — the
        // embedded certificate must be the user's, not a self-signed one.
        const MODERN_P12: &[u8] = include_bytes!("sign/fixtures/modern.p12");
        const CERT_DER: &[u8] = include_bytes!("sign/fixtures/cert.der");
        let identity = crate::sign::pkcs12::parse(MODERN_P12, "gigapdf").unwrap();

        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let signed = doc
            .sign_p12(
                &identity,
                "GigaPDF Tester",
                "Approval",
                "D:20260614120000Z",
                "Paris",
                "tester@example.com",
            )
            .unwrap();

        assert_eq!(&signed[0..5], b"%PDF-", "valid PDF header");
        let text = String::from_utf8_lossy(&signed);
        assert!(
            text.contains("adbe.pkcs7.detached"),
            "detached signature subfilter"
        );
        // The CMS /Contents (uppercase hex) must contain the imported cert DER.
        let cert_hex: String = CERT_DER.iter().map(|b| format!("{b:02X}")).collect();
        assert!(
            text.contains(&cert_hex),
            "imported certificate embedded in the signature"
        );
        assert!(Document::open(&signed).unwrap().page_count() >= 1);
    }

    #[test]
    fn signs_a_document_with_a_pades_b_t_timestamp() {
        use crate::sign::{der, timestamp};

        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let randomness: Vec<u8> = (0..256).map(|i| (i * 31 + 11) as u8).collect();
        let signer = crate::sign::Signer::generate(
            "GigaPDF Tester",
            "260614000000Z",
            "360614000000Z",
            512,
            &randomness,
        )
        .unwrap();

        // Phase 1: build the signature + the RFC 3161 request to POST.
        let request = doc
            .sign_prepare_timestamped(
                signer.key(),
                signer.certificate(),
                "GigaPDF Tester",
                "Approval",
                "D:20260614120000Z",
                "Paris",
                "tester@example.com",
                Some(&[0x11, 0x22, 0x33, 0x44]),
            )
            .unwrap();
        // The request is a well-formed TimeStampReq carrying a SHA-256 imprint.
        assert_eq!(request[0], 0x30, "TimeStampReq is a SEQUENCE");
        {
            let mut top = der::Reader::new(&request);
            let mut inner = top.descend(der::TAG_SEQUENCE).expect("seq");
            assert_eq!(
                inner.next_tag(der::TAG_INTEGER).expect("version").content,
                &[0x01]
            );
        }

        // Simulate the TSA: a token is a real CMS ContentInfo (here produced by a
        // second self-signed signer, standing in for the TSA), wrapped in a
        // granted TimeStampResp.
        let tsa = crate::sign::Signer::generate(
            "Mock TSA",
            "260101000000Z",
            "360101000000Z",
            512,
            &(0..256).map(|i| (i * 7 + 3) as u8).collect::<Vec<u8>>(),
        )
        .unwrap();
        let token_content_info = tsa.detached_cms(b"TSTInfo stand-in");
        let resp = der::sequence(&[
            der::sequence(&[der::integer_u32(0)]), // PKIStatusInfo { granted }
            token_content_info.clone(),
        ]);
        let parsed = timestamp::parse_response(&resp).expect("granted token");
        assert_eq!(parsed.status, 0);

        // Phase 2: embed the token, finalize the PDF.
        let signed = doc.sign_finish_timestamped(&parsed.token_der).unwrap();

        assert_eq!(&signed[0..5], b"%PDF-", "valid PDF header");
        let text = String::from_utf8_lossy(&signed);
        assert!(
            text.contains("ETSI.CAdES.detached"),
            "PAdES subfilter, not the legacy one"
        );
        assert!(
            !text.contains("adbe.pkcs7.detached"),
            "legacy subfilter absent"
        );
        assert!(
            !signed.windows(10).any(|w| w == b"9999999999"),
            "ByteRange placeholders patched"
        );

        // The /Contents CMS (uppercase hex) embeds the id-aa-timeStampToken OID
        // (1.2.840.113549.1.9.16.2.14) and the signing-certificate-v2 OID
        // (1.2.840.113549.1.9.16.2.47).
        let tst_oid_hex: String = der::oid(&[1, 2, 840, 113549, 1, 9, 16, 2, 14])
            .iter()
            .map(|b| format!("{b:02X}"))
            .collect();
        let scv2_oid_hex: String = der::oid(&[1, 2, 840, 113549, 1, 9, 16, 2, 47])
            .iter()
            .map(|b| format!("{b:02X}"))
            .collect();
        assert!(text.contains(&tst_oid_hex), "id-aa-timeStampToken embedded");
        assert!(
            text.contains(&scv2_oid_hex),
            "signing-certificate-v2 embedded"
        );

        // The pending state was consumed: a second finish fails.
        assert!(doc.sign_finish_timestamped(&parsed.token_der).is_err());

        // The signed file still parses.
        assert!(Document::open(&signed).unwrap().page_count() >= 1);
    }

    /// Regression: `sign_finish_timestamped` must embed the **bare**
    /// `TimeStampToken` (a CMS `ContentInfo`) in `id-aa-timeStampToken`, NOT the
    /// raw `TimeStampResp` (`SEQUENCE { PKIStatusInfo, TimeStampToken }`). The SDK
    /// hands the engine the whole TSA reply verbatim, so the unwrap must happen
    /// here (RFC 3161 §3.3.2 / ETSI EN 319 122). Feeds the RAW response and proves
    /// the attribute value is a ContentInfo, never a PKIStatusInfo-led response.
    #[test]
    fn b_t_embeds_bare_timestamp_token_not_response() {
        use crate::sign::der;

        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let signer = crate::sign::Signer::generate(
            "Signer",
            "260101000000Z",
            "360101000000Z",
            1024,
            &(0..256).map(|i| (i * 5 + 1) as u8).collect::<Vec<u8>>(),
        )
        .unwrap();
        let _request = doc
            .sign_prepare_timestamped(
                signer.key(),
                signer.certificate(),
                "Signer",
                "test",
                "D:20260614120000Z",
                "Paris",
                "tester@example.com",
                None,
            )
            .unwrap();

        // Mock TSA token (a real ContentInfo) wrapped in a granted TimeStampResp.
        let tsa = crate::sign::Signer::generate(
            "Mock TSA",
            "260101000000Z",
            "360101000000Z",
            512,
            &(0..256).map(|i| (i * 9 + 2) as u8).collect::<Vec<u8>>(),
        )
        .unwrap();
        let token_content_info = tsa.detached_cms(b"TSTInfo stand-in");
        let resp = der::sequence(&[
            der::sequence(&[der::integer_u32(0)]), // PKIStatusInfo { granted }
            token_content_info.clone(),
        ]);

        // Feed the RAW TimeStampResp — exactly what the SDK forwards.
        let signed = doc.sign_finish_timestamped(&resp).unwrap();

        let cms = extract_signature_cms(&signed).expect("signature CMS present");
        assert!(
            cms.windows(token_content_info.len())
                .any(|w| w == token_content_info.as_slice()),
            "the bare TimeStampToken ContentInfo must be embedded"
        );
        assert!(
            !cms.windows(resp.len()).any(|w| w == resp.as_slice()),
            "the TimeStampResp wrapper must NOT be embedded verbatim"
        );

        // Locate id-aa-timeStampToken (1.2.840.113549.1.9.16.2.14), then walk the
        // unsigned Attribute: SEQUENCE { OID, SET { value } }. The value must be a
        // ContentInfo (SEQUENCE whose first member is an OID), never a
        // PKIStatusInfo-led TimeStampResp (first member an INTEGER-bearing SEQ).
        let tst_oid = der::oid(&[1, 2, 840, 113549, 1, 9, 16, 2, 14]);
        let oid_at = (0..cms.len())
            .find(|&i| cms[i..].starts_with(&tst_oid))
            .expect("id-aa-timeStampToken OID found in CMS");
        // After the OID TLV comes the SET (0x31) of attribute values.
        let mut after_oid = der::Reader::new(&cms[oid_at..]);
        let _oid_tlv = after_oid.read_raw().expect("OID tlv");
        let mut set_reader = after_oid.descend(der::TAG_SET).expect("attribute SET");
        let (value, _raw) = set_reader.read_raw().expect("attribute value");
        assert_eq!(
            value.tag,
            der::TAG_SEQUENCE,
            "id-aa-timeStampToken value is a ContentInfo SEQUENCE"
        );
        let mut value_reader = value.reader();
        let (first, _) = value_reader.read_raw().expect("ContentInfo first member");
        assert_eq!(
            first.tag,
            der::TAG_OID,
            "first member of the embedded token must be the ContentInfo OID \
             (signedData), not a PKIStatusInfo — proves the TimeStampResp was unwrapped"
        );
    }

