    #[test]
    fn redaction_removes_content_from_the_stream() {
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let before = doc.page_text_runs(1).unwrap().len();
        assert!(before > 0, "fixture has text");

        // No cover: pure stream deletion so a complex background would survive.
        let removed = doc.redact_region(1, 0.0, 0.0, 612.0, 792.0, None).unwrap();
        assert!(removed > 0, "elements were removed");

        // After save + reopen, the redacted text is gone from the stream — not
        // merely covered. (A cosmetic overlay would leave the runs intact.)
        let reopened = Document::open(&doc.save()).unwrap();
        let after = reopened.page_text_runs(1).unwrap().len();
        assert!(after < before, "text runs removed ({before} → {after})");
    }

    /// Build a one-page PDF (`100×100` pt) whose only content is a `100×100`
    /// DeviceRGB image placed to fill the page (`cm 100 0 0 100 0 0`); every pixel
    /// is `fill`. Used by the PII image-pixel-overwrite tests.
    fn single_image_page(fill: [u8; 3]) -> Vec<u8> {
        let (w, h) = (100usize, 100usize);
        let mut samples = Vec::with_capacity(w * h * 3);
        for _ in 0..w * h {
            samples.extend_from_slice(&fill);
        }
        let mut body = format!(
            "<< /Type /XObject /Subtype /Image /Width {w} /Height {h} \
             /ColorSpace /DeviceRGB /BitsPerComponent 8 /Length {} >>\nstream\n",
            samples.len()
        )
        .into_bytes();
        body.extend_from_slice(&samples);
        body.extend_from_slice(b"\nendstream");
        let draw = b"q 100 0 0 100 0 0 cm /Im0 Do Q".to_vec();
        let mut content = format!("<< /Length {} >>\nstream\n", draw.len()).into_bytes();
        content.extend_from_slice(&draw);
        content.extend_from_slice(b"\nendstream");
        let objects: Vec<(u32, Vec<u8>)> = vec![
            (1, b"<< /Type /Catalog /Pages 2 0 R >>".to_vec()),
            (2, b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>".to_vec()),
            (
                3,
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 100 100] \
                  /Resources << /XObject << /Im0 6 0 R >> >> /Contents 4 0 R >>"
                    .to_vec(),
            ),
            (4, content),
            (6, body),
        ];
        raw_pdf_binary(&objects)
    }

    #[test]
    fn redact_pii_blacks_out_only_the_image_subrect() {
        // A scanned-page case: the whole page is one image. Redact the TOP band
        // (page y ∈ [60,100], full width). Afterwards the image's top rows must be
        // black and its bottom rows untouched — the sensitive sub-rectangle is
        // erased from the pixels while the rest of the scan survives.
        let mut doc = Document::open(&single_image_page([200, 30, 30])).unwrap(); // red fill
        let removed = doc.redact_pii(1, &[(0.0, 60.0, 100.0, 40.0)]).unwrap();
        assert_eq!(
            removed, 0,
            "no text/vector elements — only image pixels change"
        );

        // Pull the (re-encoded) image back out and decode it.
        let reopened = Document::open(&doc.save()).unwrap();
        let images = reopened.page_image_elements(1);
        assert_eq!(images.len(), 1, "still exactly one image element");
        let img = &images[0];
        assert_eq!(img.format, "png", "overwritten image re-encoded as PNG");
        let decoded = crate::raster::decode_png(&img.data).expect("decodes");
        let (dw, dh) = (decoded.width as usize, decoded.height as usize);
        assert_eq!((dw, dh), (100, 100), "dimensions preserved");
        let texel = |row: usize, col: usize| -> [u8; 4] {
            let i = (row * dw + col) * 4;
            [
                decoded.rgba[i],
                decoded.rgba[i + 1],
                decoded.rgba[i + 2],
                decoded.rgba[i + 3],
            ]
        };
        // Image row 0 = top of the page (high y). The redacted top band → black.
        let top = texel(5, 50);
        assert_eq!(
            [top[0], top[1], top[2]],
            [0, 0, 0],
            "redacted top band pixel must be black, got {top:?}"
        );
        assert_eq!(top[3], 255, "blacked pixel is opaque (no leak behind it)");
        // The bottom of the page (low y, outside the rect) keeps the original red.
        let bottom = texel(95, 50);
        assert!(
            bottom[0] > 150 && bottom[1] < 80 && bottom[2] < 80,
            "untouched bottom pixel must keep original red, got {bottom:?}"
        );
    }

    #[test]
    fn redact_pii_removes_text_and_paints_black_cover() {
        // Text-bearing page: redact the whole page. The text is physically removed
        // from the stream (uncopyable) AND an opaque black box is painted as the
        // visible mark (the PII default — no cover argument needed).
        let mut doc = Document::open(&fixture("simple-text.pdf")).unwrap();
        let before = doc.page_text_runs(1).unwrap().len();
        assert!(before > 0, "fixture has text");
        let (pw, ph, _) = doc.page_info(1).unwrap();

        let removed = doc.redact_pii(1, &[(0.0, 0.0, pw, ph)]).unwrap();
        assert!(removed > 0, "text elements were deleted");

        let reopened = Document::open(&doc.save()).unwrap();

        // 1. Copy/paste & extraction reveal nothing in the zone: the runs are gone
        //    from the stream, not merely hidden under the cover.
        let runs = reopened.page_text_runs(1).unwrap();
        assert!(
            runs.is_empty(),
            "no recoverable text in the redacted zone (got {} runs)",
            runs.len()
        );
        assert!(
            reopened.page_text_elements(1).is_empty(),
            "structured extraction also reveals nothing in the zone"
        );

        // 2. A visible opaque black box covers the zone (rasterize and sample the
        //    centre — it must be black, not the white paper).
        let canvas = reopened.render_page_canvas(1, 1.0, false).unwrap();
        let mid = px(&canvas, canvas.width / 2, canvas.height / 2);
        assert_eq!(
            mid,
            [0, 0, 0],
            "centre of the page is the black redaction cover, got {mid:?}"
        );
    }

    #[test]
    fn redact_pii_multiple_rects_in_one_call() {
        // Two disjoint bands on the single-image page redacted in ONE call: both
        // are blacked out, the gap between them is untouched.
        let mut doc = Document::open(&single_image_page([40, 60, 220])).unwrap(); // blue fill
        doc.redact_pii(1, &[(0.0, 80.0, 100.0, 20.0), (0.0, 0.0, 100.0, 20.0)])
            .unwrap();
        let reopened = Document::open(&doc.save()).unwrap();
        let img = &reopened.page_image_elements(1)[0];
        let decoded = crate::raster::decode_png(&img.data).expect("decodes");
        let dw = decoded.width as usize;
        let rgb = |row: usize, col: usize| -> [u8; 3] {
            let i = (row * dw + col) * 4;
            [decoded.rgba[i], decoded.rgba[i + 1], decoded.rgba[i + 2]]
        };
        assert_eq!(rgb(5, 50), [0, 0, 0], "top band redacted");
        assert_eq!(rgb(95, 50), [0, 0, 0], "bottom band redacted");
        // Middle row (page y ≈ 50, outside both bands) keeps original blue.
        let mid = rgb(50, 50);
        assert!(
            mid[2] > 150 && mid[0] < 90,
            "middle band untouched, got {mid:?}"
        );
    }

    #[test]
    fn encrypts_and_decrypts_round_trip() {
        let original = Document::open(&fixture("simple-text.pdf")).unwrap();
        let want: String = original
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert!(!want.is_empty());

        let encrypted = original.save_encrypted(b"s3cret", b"", b"file-id-bytes-01", b"", 0, -44);

        // Opening with the right password recovers the exact text.
        let opened = Document::open_with_password(&encrypted, b"s3cret").unwrap();
        let got: String = opened
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert_eq!(got, want, "decrypted text matches original");

        // The wrong (empty) password is rejected at open time.
        assert!(
            Document::open(&encrypted).is_err(),
            "wrong password must be rejected"
        );
    }

    #[test]
    fn change_passwords_and_remove_encryption_round_trip() {
        let original = Document::open(&fixture("simple-text.pdf")).unwrap();
        let want: String = original
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert!(!want.is_empty());

        let enc =
            original.save_encrypted(b"old-user", b"old-owner", b"id-bytes-0001234", b"", 0, -44);
        let opened = Document::open_with_password(&enc, b"old-user").unwrap();

        // Change passwords (re-encrypt) — the old /Encrypt is discarded.
        let reenc = opened.change_passwords(
            b"new-user",
            b"new-owner",
            b"id-bytes-0001234",
            b"",
            0,
            -44,
            true,
        );
        assert!(
            Document::open_with_password(&reenc, b"old-user").is_err(),
            "old password rejected after change"
        );
        let reopened = Document::open_with_password(&reenc, b"new-user").unwrap();
        let got: String = reopened
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert_eq!(got, want, "text survives re-encryption");

        // Remove encryption — plaintext, opens with no password.
        let plain = opened.remove_encryption();
        let plain_doc = Document::open(&plain).unwrap();
        let got2: String = plain_doc
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert_eq!(got2, want, "text survives decryption");

        // /EncryptMetadata = false (AES-128) round-trips and emits the flag.
        let enc_nm =
            original.save_encrypted_ex(b"u", b"o", b"id-bytes-0001234", b"", 1, -44, false);
        assert!(
            String::from_utf8_lossy(&enc_nm).contains("/EncryptMetadata"),
            "EncryptMetadata flag emitted"
        );
        assert!(
            Document::open_with_password(&enc_nm, b"u").is_ok(),
            "metadata-unencrypted AES-128 still opens"
        );
    }

    #[test]
    fn pubsec_encrypt_open_round_trip() {
        let original = Document::open(&fixture("simple-text.pdf")).unwrap();
        let want: String = original
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert!(!want.is_empty());

        let randomness: Vec<u8> = (0..256).map(|i| (i * 53 + 7) as u8).collect();
        let recipient = crate::sign::Signer::generate(
            "Recipient",
            "260101000000Z",
            "320101000000Z",
            2048,
            &randomness,
        )
        .unwrap();
        let cert = recipient.certificate().to_vec();
        let key = recipient.key().to_pkcs1_der().unwrap();
        let seed: Vec<u8> = (0..20).map(|i| (i * 7 + 1) as u8).collect();
        let rng_seed: Vec<u8> = (0..48).map(|i| (i * 11 + 3) as u8).collect();

        // AES-128 public-key encryption.
        let enc = original
            .encrypt_for_recipients(std::slice::from_ref(&cert), -44, false, true, &seed, &rng_seed)
            .unwrap();
        assert!(
            String::from_utf8_lossy(&enc).contains("/Adobe.PubSec"),
            "public-key handler written"
        );
        // No password can open it (it is not a standard-handler file).
        assert!(Document::open(&enc).is_err());
        // The recipient's private key recovers the exact text.
        let opened = Document::open_with_private_key(&enc, &cert, &key).unwrap();
        let got: String = opened
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert_eq!(got, want, "recipient decrypts the document");

        // A stranger's key is rejected.
        let stranger = crate::sign::Signer::generate(
            "Stranger",
            "260101000000Z",
            "320101000000Z",
            2048,
            &(0..256).map(|i| (i * 29 + 5) as u8).collect::<Vec<u8>>(),
        )
        .unwrap();
        assert!(
            Document::open_with_private_key(
                &enc,
                stranger.certificate(),
                &stranger.key().to_pkcs1_der().unwrap()
            )
            .is_err(),
            "a non-recipient key cannot open the file"
        );

        // AES-256 public-key encryption round-trips too.
        let enc3 = original
            .encrypt_for_recipients(std::slice::from_ref(&cert), -44, true, true, &seed, &rng_seed)
            .unwrap();
        let opened3 = Document::open_with_private_key(&enc3, &cert, &key).unwrap();
        let got3: String = opened3
            .page_text_runs(1)
            .unwrap()
            .iter()
            .map(|r| r.text.clone())
            .collect();
        assert_eq!(got3, want, "AES-256 recipient decrypts the document");
    }

    #[test]
    fn to_tagged_emits_struct_tree_role_map_and_pdf_ua_id() {
        let html = "<h1>Accessible Title</h1><p>A paragraph of body text to tag.</p>\
                    <p>Another paragraph with more words.</p>";
        let src = crate::convert::reverse::html_to_pdf(html);
        let doc = Document::open(&src).unwrap();

        let tagged = doc.to_tagged(true);
        let s = String::from_utf8_lossy(&tagged);
        assert!(s.contains("/StructTreeRoot"), "struct tree root");
        assert!(s.contains("/MarkInfo"), "mark info");
        assert!(s.contains("/Marked true"), "marked true");
        assert!(s.contains("/Lang"), "document language");
        assert!(s.contains("/RoleMap"), "role map");
        assert!(s.contains("pdfuaid:part>1"), "PDF/UA-1 identifier");
        // Tagged, but NOT forced into PDF/A (no pdfaid metadata).
        assert!(!s.contains("pdfaid"), "not PDF/A");
        let reopened = Document::open(&tagged).unwrap();
        assert!(reopened.page_count() >= 1, "tagged PDF round-trips");

        // Without `pdf_ua`: still tagged, but no PDF/UA identifier.
        let plain = doc.to_tagged(false);
        let p = String::from_utf8_lossy(&plain);
        assert!(p.contains("/StructTreeRoot"), "still tagged");
        assert!(!p.contains("pdfuaid"), "no UA id when pdf_ua = false");
    }

    #[test]
    fn add_gradient_paints_linear_and_radial_and_round_trips() {
        let mut doc = blank_doc();
        doc.add_gradient(
            1,
            &GradientSpec {
                kind: GradientKind::Linear {
                    x0: 50.0,
                    y0: 50.0,
                    x1: 250.0,
                    y1: 50.0,
                },
                stops: vec![
                    GradientStop {
                        offset: 0.0,
                        color: [1.0, 0.0, 0.0],
                    },
                    GradientStop {
                        offset: 0.5,
                        color: [0.0, 1.0, 0.0],
                    },
                    GradientStop {
                        offset: 1.0,
                        color: [0.0, 0.0, 1.0],
                    },
                ],
                rect: [50.0, 40.0, 200.0, 60.0],
                extend: (true, true),
                opacity: 1.0,
            },
        )
        .unwrap();
        doc.add_gradient(
            1,
            &GradientSpec {
                kind: GradientKind::Radial {
                    x0: 150.0,
                    y0: 200.0,
                    r0: 0.0,
                    x1: 150.0,
                    y1: 200.0,
                    r1: 80.0,
                },
                stops: vec![
                    GradientStop {
                        offset: 0.0,
                        color: [1.0, 1.0, 1.0],
                    },
                    GradientStop {
                        offset: 1.0,
                        color: [0.2, 0.2, 0.8],
                    },
                ],
                rect: [70.0, 120.0, 160.0, 160.0],
                extend: (true, true),
                opacity: 0.9,
            },
        )
        .unwrap();

        let bytes = doc.save();
        let s = String::from_utf8_lossy(&bytes);
        assert!(s.contains("/ShadingType 2"), "axial shading written");
        assert!(s.contains("/ShadingType 3"), "radial shading written");
        assert!(s.contains("/PatternType 2"), "shading pattern written");
        assert!(s.contains("/Pattern cs"), "pattern colour space selected");

        let reopened = Document::open(&bytes).unwrap();
        assert_eq!(reopened.page_count(), 1);
        let content = String::from_utf8_lossy(&reopened.page_content(1).unwrap()).into_owned();
        assert!(
            content.contains("scn"),
            "pattern fill op present after reopen"
        );

        // Fewer than two stops is rejected.
        assert!(doc
            .add_gradient(
                1,
                &GradientSpec {
                    kind: GradientKind::Linear {
                        x0: 0.0,
                        y0: 0.0,
                        x1: 1.0,
                        y1: 0.0,
                    },
                    stops: vec![GradientStop {
                        offset: 0.0,
                        color: [0.0, 0.0, 0.0],
                    }],
                    rect: [0.0, 0.0, 1.0, 1.0],
                    extend: (false, false),
                    opacity: 1.0,
                },
            )
            .is_err());
    }

